mapper.select:
SELECT sut.user_id, sut.tenant_id, t.tenant_name, t.tenant_status, t.expire_time, sut.member_type, sut.is_default, sut.status FROM sys_user_tenant sut INNER JOIN sys_tenant t ON t.id = sut.tenant_id WHERE sut.user_id = #{userId}
AND sut.status = 1 AND t.tenant_status = 1 AND (t.expire_time IS NULL OR t.expire_time > NOW())
ORDER BY sut.is_default DESC, t.id ASC
